import { useCallback, useRef } from 'react';

function useDebouncedCallback<T extends (...args: any[]) => void>(
  fn: T, delay: number
): T {
  const timer = useRef<ReturnType<typeof setTimeout> | null>(null);
  return useCallback(
    (...args: Parameters<T>) => {
      if (timer.current) clearTimeout(timer.current);
      timer.current = setTimeout(() => fn(...args), delay);
    },
    [fn, delay]
  ) as T;
}

export default useDebouncedCallback;

import { useState, useRef, useCallback } from 'react';

function useRafState<S>(initialState: S) {
  const frame = useRef<number>(0);
  const [state, setState] = useState<S>(initialState);

  const setRafState = useCallback((value: S | ((prev: S) => S)) => {
    cancelAnimationFrame(frame.current);
    frame.current = requestAnimationFrame(() => { setState(value); });
  }, []);

  return [state, setRafState] as const;
}

export default useRafState;

import { useState, useEffect, useRef } from 'react';

function useBroadcastChannel<T>(channelName: string) {
  const [message, setMessage] = useState<T | null>(null);
  const channel = useRef<BroadcastChannel | null>(null);

  useEffect(() => {
    channel.current = new BroadcastChannel(channelName);
    channel.current.onmessage = (e) => setMessage(e.data as T);
    return () => channel.current?.close();
  }, [channelName]);

  const postMessage = (data: T) => channel.current?.postMessage(data);
  return { message, postMessage };
}

export default useBroadcastChannel;

import { useState, useEffect } from 'react';

function useEventSource(url: string) {
  const [data, setData] = useState<string | null>(null);
  const [error, setError] = useState<Event | null>(null);
  const [readyState, setReadyState] = useState<number>(EventSource.CONNECTING);

  useEffect(() => {
    const es = new EventSource(url);
    es.onopen = () => setReadyState(es.readyState);
    es.onmessage = (e) => setData(e.data);
    es.onerror = (e) => { setError(e); setReadyState(es.readyState); };
    return () => es.close();
  }, [url]);

  return { data, error, readyState };
}

export default useEventSource;

import { useState, useEffect, useRef, useCallback } from 'react';

function useWebSocket(url: string) {
  const ws = useRef<WebSocket | null>(null);
  const [lastMessage, setLastMessage] = useState<string | null>(null);
  const [readyState, setReadyState] = useState<number>(WebSocket.CONNECTING);

  useEffect(() => {
    ws.current = new WebSocket(url);
    ws.current.onopen = () => setReadyState(WebSocket.OPEN);
    ws.current.onclose = () => setReadyState(WebSocket.CLOSED);
    ws.current.onmessage = (e) => setLastMessage(e.data);
    return () => ws.current?.close();
  }, [url]);

  const sendMessage = useCallback((msg: string) => ws.current?.send(msg), []);
  return { lastMessage, readyState, sendMessage };
}

export default useWebSocket;

import { useState, useEffect } from 'react';

function useOnlineStatus(): boolean {
  const [isOnline, setIsOnline] = useState<boolean>(navigator.onLine);

  useEffect(() => {
    const on = () => setIsOnline(true);
    const off = () => setIsOnline(false);
    window.addEventListener('online', on);
    window.addEventListener('offline', off);
    return () => {
      window.removeEventListener('online', on);
      window.removeEventListener('offline', off);
    };
  }, []);

  return isOnline;
}

export default useOnlineStatus;

