import { useCallback, Ref, MutableRefObject } from 'react';

function setRef<T>(ref: Ref<T> | undefined, value: T) {
  if (!ref) return;
  if (typeof ref === 'function') ref(value);
  else (ref as MutableRefObject<T>).current = value;
}

function useMergedRefs<T>(...refs: Array<Ref<T> | undefined>) {
  return useCallback(
    (node: T) => refs.forEach((r) => setRef(r, node)),
    refs
  );
}

export default useMergedRefs;

import { useState, useEffect } from 'react';

type ColorScheme = 'light' | 'dark';

function usePreferredColorScheme(): ColorScheme {
  const mq = window.matchMedia('(prefers-color-scheme: dark)');
  const [scheme, setScheme] = useState<ColorScheme>(mq.matches ? 'dark' : 'light');

  useEffect(() => {
    const handler = (e: MediaQueryListEvent) =>
      setScheme(e.matches ? 'dark' : 'light');
    mq.addEventListener('change', handler);
    return () => mq.removeEventListener('change', handler);
  }, []);

  return scheme;
}

export default usePreferredColorScheme;

import { useEffect } from 'react';

function useBeforeUnload(enabled: boolean, message = 'ļ│ĆĻ▓Į ņé¼ĒĢŁņØ┤ ņĀĆņ×źļÉśņ¦Ć ņĢŖņĢśņŖĄļŗłļŗż.') {
  useEffect(() => {
    if (!enabled) return;
    const handler = (e: BeforeUnloadEvent) => {
      e.preventDefault();
      e.returnValue = message;
    };
    window.addEventListener('beforeunload', handler);
    return () => window.removeEventListener('beforeunload', handler);
  }, [enabled, message]);
}

export default useBeforeUnload;

import { useEffect, useRef } from 'react';

function useUnmountEffect(fn: () => void) {
  const fnRef = useRef(fn);
  fnRef.current = fn;
  useEffect(() => () => fnRef.current(), []);
}

export default useUnmountEffect;

import { useState, useCallback } from 'react';

function useToggleArray<T>(initial: T[] = []) {
  const [arr, setArr] = useState<T[]>(initial);

  const toggle = useCallback((item: T) => {
    setArr((prev) =>
      prev.includes(item) ? prev.filter((v) => v !== item) : [...prev, item]
    );
  }, []);

  const has = (item: T) => arr.includes(item);
  const clear = () => setArr([]);

  return { arr, toggle, has, clear };
}

export default useToggleArray;

import { useState, useCallback } from 'react';

function useCycle<T>(items: T[]): [T, () => void, () => void] {
  const [index, setIndex] = useState(0);
  const n = items.length;

  const next = useCallback(() => setIndex((i) => (i + 1) % n), [n]);
  const prev = useCallback(() => setIndex((i) => (i - 1 + n) % n), [n]);

  return [items[index], next, prev];
}

export default useCycle;

import { useState, useCallback } from 'react';

function useList<T>(initial: T[] = []) {
  const [list, setList] = useState<T[]>(initial);

  const push = useCallback((item: T) => setList((l) => [...l, item]), []);
  const remove = useCallback((index: number) =>
    setList((l) => l.filter((_, i) => i !== index)), []);
  const update = useCallback((index: number, item: T) =>
    setList((l) => l.map((v, i) => (i === index ? item : v))), []);
  const clear = useCallback(() => setList([]), []);

  return { list, push, remove, update, clear };
}

export default useList;

import { useState, useCallback } from 'react';

function useObjectState<T extends object>(initial: T) {
  const [state, setState] = useState<T>(initial);

  const patch = useCallback((partial: Partial<T>) =>
    setState((prev) => ({ ...prev, ...partial })), []);
  const reset = useCallback(() => setState(initial), [initial]);

  return [state, patch, reset] as const;
}

export default useObjectState;

import { useState, useCallback } from 'react';

interface Options { min?: number; max?: number; step?: number; }

function useCounterWithStep(initial = 0, { min = -Infinity, max = Infinity, step = 1 }: Options = {}) {
  const [count, setCount] = useState(initial);

  const inc = useCallback(() => setCount((c) => Math.min(c + step, max)), [step, max]);
  const dec = useCallback(() => setCount((c) => Math.max(c - step, min)), [step, min]);
  const reset = useCallback(() => setCount(initial), [initial]);

  return { count, inc, dec, reset };
}

export default useCounterWithStep;

import { useEffect } from 'react';

function useLockBodyScroll(locked: boolean) {
  useEffect(() => {
    if (!locked) return;
    const original = document.body.style.overflow;
    document.body.style.overflow = 'hidden';
    return () => { document.body.style.overflow = original; };
  }, [locked]);
}

export default useLockBodyScroll;

import { useState, useEffect, useCallback } from 'react';

function useHash() {
  const [hash, setHashState] = useState<string>(() => window.location.hash);

  useEffect(() => {
    const handler = () => setHashState(window.location.hash);
    window.addEventListener('hashchange', handler);
    return () => window.removeEventListener('hashchange', handler);
  }, []);

  const setHash = useCallback((h: string) => { window.location.hash = h; }, []);
