import { useState, useEffect, useRef } from 'react';

type Direction = 'up' | 'down' | null;

function useScrollDirection(): Direction {
  const [dir, setDir] = useState<Direction>(null);
  const prevY = useRef(0);

  useEffect(() => {
    const handler = () => {
      const y = window.scrollY;
      setDir(y > prevY.current ? 'down' : 'up');
      prevY.current = y;
    };
    window.addEventListener('scroll', handler, { passive: true });
    return () => window.removeEventListener('scroll', handler);
  }, []);

  return dir;
}

export default useScrollDirection;

import { useEffect, useState } from 'react';

function useImagePreload(urls: string[]) {
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    if (!urls.length) { setLoaded(true); return; }
    let done = 0;
    urls.forEach((src) => {
      const img = new Image();
      img.onload = img.onerror = () => {
        done++;
        if (done === urls.length) setLoaded(true);
      };
      img.src = src;
    });
  }, [urls]);

  return loaded;
}

export default useImagePreload;

import { useState, useCallback } from 'react';

function useRetry<T>(fn: () => Promise<T>, maxRetries = 3) {
  const [data, setData] = useState<T | null>(null);
  const [error, setError] = useState<Error | null>(null);
  const [loading, setLoading] = useState(false);

  const run = useCallback(async () => {
    setLoading(true); setError(null);
    for (let i = 0; i <= maxRetries; i++) {
      try {
        const result = await fn();
        setData(result); setLoading(false); return;
      } catch (e) {
        if (i === maxRetries) { setError(e as Error); setLoading(false); }
      }
    }
  }, [fn, maxRetries]);

  return { data, error, loading, run };
}

export default useRetry;

import { useState, useEffect, useRef } from 'react';

function usePollingFetch<T>(url: string, interval = 5000) {
  const [data, setData] = useState<T | null>(null);
  const [error, setError] = useState<Error | null>(null);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await fetch(url);
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        setData(await res.json());
      } catch (e) { setError(e as Error); }
    };

    fetchData();
    timerRef.current = setInterval(fetchData, interval);
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [url, interval]);

  return { data, error };
}

export default usePollingFetch;

import { useState, useEffect } from 'react';

function useTextSelection() {
  const [selectedText, setSelectedText] = useState<string>('');

  useEffect(() => {
    const handler = () => {
      const selection = window.getSelection();
      setSelectedText(selection ? selection.toString() : '');
    };
    document.addEventListener('selectionchange', handler);
    return () => document.removeEventListener('selectionchange', handler);
  }, []);

  return selectedText;
}

export default useTextSelection;

import { useState, useEffect } from 'react';

interface MotionData {
  x: number | null; y: number | null; z: number | null;
}

function useDeviceMotion() {
  const [motion, setMotion] = useState<MotionData>({ x: null, y: null, z: null });

  useEffect(() => {
    const handler = (e: DeviceMotionEvent) => {
      const acc = e.accelerationIncludingGravity;
      if (acc) setMotion({ x: acc.x, y: acc.y, z: acc.z });
    };
    window.addEventListener('devicemotion', handler);
    return () => window.removeEventListener('devicemotion', handler);
  }, []);

  return motion;
}

export default useDeviceMotion;

import { useState, useCallback } from 'react';

function useShare() {
  const [shared, setShared] = useState(false);
  const [error, setError] = useState<Error | null>(null);

  const share = useCallback(async (data: ShareData) => {
    if (!navigator.share) {
      setError(new Error('Web Share API ļ»Ėņ¦ĆņøÉ'));
      return;
    }
    try {
      await navigator.share(data);
      setShared(true);
    } catch (e) {
      if ((e as Error).name !== 'AbortError') setError(e as Error);
    }
  }, []);

  return { share, shared, error };
}

export default useShare;

import { useState, useCallback, useEffect, useRef } from 'react';

function useWakeLock() {
  const [active, setActive] = useState(false);
  const lockRef = useRef<WakeLockSentinel | null>(null);

  const request = useCallback(async () => {
    try {
      lockRef.current = await navigator.wakeLock.request('screen');
      lockRef.current.onrelease = () => setActive(false);
      setActive(true);
    } catch { setActive(false); }
  }, []);

  const release = useCallback(async () => {
    await lockRef.current?.release();
    setActive(false);
  }, []);

  useEffect(() => () => { lockRef.current?.release(); }, []);

  return { active, request, release };
}

export default useWakeLock;

import { useState, useEffect } from 'react';

function usePermission(name: PermissionName) {
  const [state, setState] = useState<PermissionState>('prompt');

  useEffect(() => {
    let permissionStatus: PermissionStatus;
    navigator.permissions.query({ name }).then((status) => {
      permissionStatus = status;
      setState(status.state);
      status.onchange = () => setState(status.state);
    }).catch(() => setState('denied'));

    return () => {
      if (permissionStatus) permissionStatus.onchange = null;
    };
  }, [name]);

  return state;
}

export default usePermission;

import { useState, useCallback } from 'react';

function useClipboardHistory(maxSize = 10) {
  const [history, setHistory] = useState<string[]>([]);

  const copy = useCallback(async (text: string) => {
    try {
      await navigator.clipboard.writeText(text);
      setHistory((prev) => {
        const next = [text, ...prev.filter((v) => v !== text)];
        return next.slice(0, maxSize);
      });
      return true;
    } catch { return false; }
  }, [maxSize]);

  const clear = useCallback(() => setHistory([]), []);

  return { history, copy, clear };
}

export default useClipboardHistory;

import { useState, useEffect } from 'react';

function useReachBottom(threshold = 100): boolean {
  const [reached, setReached] = useState(false);

  useEffect(() => {
    const handler = () => {
      const { scrollTop, scrollHeight, clientHeight } = document.documentElement;
      setReached(scrollHeight - scrollTop - clientHeight <= threshold);
    };
    window.addEventListener('scroll', handler, { passive: true });
    return () => window.removeEventListener('scroll', handler);
  }, [threshold]);

  return reached;
}

export default useReachBottom;

import { useCallback } from 'react';

function useVibrate() {
  const vibrate = useCallback((pattern: number | number[]) => {
    if (!('vibrate' in navigator)) return false;
    return navigator.vibrate(pattern);
  }, []);

  const stop = useCallback(() => {
    if (!('vibrate' in navigator)) return;
    navigator.vibrate(0);
  }, []);

  return { vibrate, stop };
}

export default useVibrate;

