import { useState } from 'react';

interface Props { initialScore?: number; }

function VoteWidget({ initialScore = 0 }: Props) {
  const [score, setScore] = useState(initialScore);
  const [vote, setVote] = useState<'up' | 'down' | null>(null);

  const handleVote = (dir: 'up' | 'down') => {
    if (vote === dir) {
      setScore((s) => s + (dir === 'up' ? -1 : 1));
      setVote(null);
    } else {
      const delta = dir === 'up' ? 1 : -1;
      setScore((s) => s + delta + (vote ? delta : 0));
      setVote(dir);
    }
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 4, width: 40 }}>
      <button onClick={() => handleVote('up')} style={{ color: vote === 'up' ? 'orange' : 'gray', background: 'none', border: 'none', cursor: 'pointer', fontSize: 18 }}>Ō¢▓</button>
      <span style={{ fontWeight: 'bold' }}>{score}</span>
      <button onClick={() => handleVote('down')} style={{ color: vote === 'down' ? 'blue' : 'gray', background: 'none', border: 'none', cursor: 'pointer', fontSize: 18 }}>Ō¢╝</button>
    </div>
  );
}

export default VoteWidget;

import React from 'react';

interface Props {
  userRoles: string[];
  requiredRoles: string[];
  fallback?: React.ReactNode;
