import React from 'react';

interface Props { data: number[]; width?: number; height?: number; color?: string; }

function Sparkline({ data, width = 120, height = 40, color = '#3b82f6' }: Props) {
  if (data.length < 2) return null;
  const min = Math.min(...data);
  const max = Math.max(...data);
  const range = max - min || 1;
  const step = width / (data.length - 1);

  const points = data
    .map((v, i) => `${i * step},${height - ((v - min) / range) * height}`)
    .join(' ');

  return (
    <svg width={width} height={height} style={{ overflow: 'visible' }}>
      <polyline fill="none" stroke={color} strokeWidth={2} points={points} />
    </svg>
  );
}

export default Sparkline;

import React from 'react';

interface Props { value: number; max?: number; size?: number; strokeWidth?: number; color?: string; }

function Gauge({ value, max = 100, size = 120, strokeWidth = 10, color = '#3b82f6' }: Props) {
  const radius = (size - strokeWidth) / 2;
  const circumference = 2 * Math.PI * radius;
  const progress = Math.min(value / max, 1);
  const offset = circumference * (1 - progress);
  const cx = size / 2;

  return (
    <svg width={size} height={size}>
      <circle cx={cx} cy={cx} r={radius} fill="none" stroke="#e5e7eb" strokeWidth={strokeWidth} />
      <circle cx={cx} cy={cx} r={radius} fill="none" stroke={color} strokeWidth={strokeWidth}
        strokeDasharray={circumference} strokeDashoffset={offset}
        strokeLinecap="round" transform={`rotate(-90 ${cx} ${cx})`} />
      <text x={cx} y={cx} textAnchor="middle" dominantBaseline="central" fontSize={size * 0.22} fontWeight="bold">
        {Math.round(progress * 100)}%
      </text>
    </svg>
  );
}

export default Gauge;

