import { useState, useCallback } from 'react';

function useTransferList(initialLeft: string[], initialRight: string[]) {
  const [left, setLeft] = useState(initialLeft);
  const [right, setRight] = useState(initialRight);
  const [sel, setSel] = useState<{ side: 'left' | 'right'; items: string[] }>({
    side: 'left', items: [],
  });

  const toggleSel = useCallback((side: 'left' | 'right', item: string) => {
    setSel((s) =>
      s.side !== side
        ? { side, items: [item] }
        : { side, items: s.items.includes(item) ? s.items.filter((v) => v !== item) : [...s.items, item] }
    );
  }, []);

  const moveRight = useCallback(() => {
    setRight((r) => [...r, ...sel.items]);
    setLeft((l) => l.filter((v) => !sel.items.includes(v)));
    setSel({ side: 'left', items: [] });
  }, [sel]);

  const moveLeft = useCallback(() => {
    setLeft((l) => [...l, ...sel.items]);
    setRight((r) => r.filter((v) => !sel.items.includes(v)));
    setSel({ side: 'right', items: [] });
  }, [sel]);

  return { left, right, sel, toggleSel, moveRight, moveLeft };
}

export default useTransferList;

