import { useRef, useState, useEffect } from 'react';

interface Props { width?: number; height?: number; onSave?: (dataUrl: string) => void; }

function SignaturePad({ width = 400, height = 200, onSave }: Props) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const drawing = useRef(false);

  const getCtx = () => canvasRef.current?.getContext('2d');

  const start = (e: React.MouseEvent) => {
    drawing.current = true;
    const ctx = getCtx(); if (!ctx) return;
    const rect = canvasRef.current!.getBoundingClientRect();
    ctx.beginPath();
    ctx.moveTo(e.clientX - rect.left, e.clientY - rect.top);
  };

  const draw = (e: React.MouseEvent) => {
    if (!drawing.current) return;
    const ctx = getCtx(); if (!ctx) return;
    const rect = canvasRef.current!.getBoundingClientRect();
    ctx.lineTo(e.clientX - rect.left, e.clientY - rect.top);
    ctx.strokeStyle = '#000'; ctx.lineWidth = 2;
    ctx.stroke();
  };

  const stop = () => { drawing.current = false; };
  const clear = () => getCtx()?.clearRect(0, 0, width, height);
  const save = () => onSave?.(canvasRef.current?.toDataURL() ?? '');

  return (
    <div>
      <canvas ref={canvasRef} width={width} height={height}
        style={{ border: '1px solid #d1d5db', borderRadius: 6, cursor: 'crosshair' }}
        onMouseDown={start} onMouseMove={draw} onMouseUp={stop} onMouseLeave={stop} />
      <div style={{ marginTop: 8, display: 'flex', gap: 8 }}>
        <button onClick={clear}>ņ¦ĆņÜ░ĻĖ░</button>
        <button onClick={save}>ņĀĆņ×ź</button>
      </div>
    </div>
  );
}

export default SignaturePad;

