interface Props { left: React.ReactNode; right: React.ReactNode; defaultSplit?: number; }

function SplitPane({ left, right, defaultSplit = 50 }: Props) {
  const [split, setSplit] = useState(defaultSplit);
  const dragging = useRef(false);
  const containerRef = useRef<HTMLDivElement>(null);

  const onMouseDown = () => { dragging.current = true; };

  const onMouseMove = useCallback((e: React.MouseEvent) => {
    if (!dragging.current || !containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const pct = ((e.clientX - rect.left) / rect.width) * 100;
    setSplit(Math.min(80, Math.max(20, pct)));
  }, []);

  const onMouseUp = () => { dragging.current = false; };

  return (
    <div ref={containerRef} style={{ display: 'flex', height: '100%', userSelect: 'none' }}
      onMouseMove={onMouseMove} onMouseUp={onMouseUp} onMouseLeave={onMouseUp}>
      <div style={{ width: `${split}%`, overflow: 'auto' }}>{left}</div>
      <div onMouseDown={onMouseDown} style={{ width: 4, background: '#d1d5db', cursor: 'col-resize', flexShrink: 0 }} />
      <div style={{ flex: 1, overflow: 'auto' }}>{right}</div>
