interface Props { total: number; page: number; onChange: (p: number) => void; }

function paginate(current: number, total: number): (number | '...')[] {
  const pages: (number | '...')[] = [];
  for (let i = 1; i <= total; i++) {
    if (i === 1 || i === total || (i >= current - 1 && i <= current + 1)) pages.push(i);
    else if (pages[pages.length - 1] !== '...') pages.push('...');
  }
  return pages;
}

function Pagination({ total, page, onChange }: Props) {
  const pages = paginate(page, total);
  return (
    <nav style={{ display: 'flex', gap: 4 }}>
      <button disabled={page === 1} onClick={() => onChange(page - 1)}>ņØ┤ņĀä</button>
      {pages.map((p, i) =>
        p === '...' ? <span key={i} style={{ padding: '4px 8px' }}>ŌĆ”</span> : (
          <button key={p} onClick={() => onChange(p as number)}
            style={{ fontWeight: page === p ? 700 : 400 }}>{p}</button>
        )
      )}
      <button disabled={page === total} onClick={() => onChange(page + 1)}>ļŗżņØī</button>
    </nav>
  );
}

export default Pagination;

