type DateRange = { start: Date | null; end: Date | null };

function useRangePicker() {
  const [range, setRange] = useState<DateRange>({ start: null, end: null });

  const select = useCallback((d: Date) => {
    setRange((prev) => {
      if (!prev.start || prev.end) return { start: d, end: null };
      if (d < prev.start) return { start: d, end: prev.start };
      return { start: prev.start, end: d };
    });
  }, []);

  const clear = useCallback(() => setRange({ start: null, end: null }), []);

  const inRange = useCallback(
    (d: Date) => !!(range.start && range.end && d >= range.start && d <= range.end),
    [range]
  );

  return { range, select, clear, inRange };
}

export default useRangePicker;

import { useState, useEffect } from 'react';

function formatAgo(date: Date): string {
  const seconds = Math.floor((Date.now() - date.getTime()) / 1000);
  if (seconds < 60) return `${seconds}ņ┤ł ņĀä`;
  const minutes = Math.floor(seconds / 60);
  if (minutes < 60) return `${minutes}ļČä ņĀä`;
  const hours = Math.floor(minutes / 60);
  if (hours < 24) return `${hours}ņŗ£Ļ░ä ņĀä`;
  const days = Math.floor(hours / 24);
  return `${days}ņØ╝ ņĀä`;
}

function TimeAgo({ date }: { date: Date }) {
  const [label, setLabel] = useState(() => formatAgo(date));

  useEffect(() => {
    const id = setInterval(() => setLabel(formatAgo(date)), 30000);
    return () => clearInterval(id);
  }, [date]);

  return <time dateTime={date.toISOString()} title={date.toLocaleString()}>{label}</time>;
}

