function applyMask(raw: string, mask: string): string {
  const digits = raw.replace(/\D/g, '');
  let di = 0;
  return mask.split('').map((ch) => {
    if (ch === '9') return di < digits.length ? digits[di++] : '';
    return di < digits.length ? ch : '';
  }).join('');
}

interface Props { mask: string; placeholder?: string; onChange?: (v: string) => void; }

function MaskedInput({ mask, placeholder, onChange }: Props) {
  const [value, setValue] = useState('');

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const masked = applyMask(e.target.value, mask);
    setValue(masked);
    onChange?.(masked);
  };

  return (
    <input value={value} onChange={handleChange} placeholder={placeholder ?? mask.replace(/9/g, '_')}
      style={{ padding: '8px 12px', border: '1px solid #d1d5db', borderRadius: 6, fontFamily: 'monospace', fontSize: 15 }} />
  );
}

export default MaskedInput;

import { useState } from 'react';

function luminance(hex: string): number {
  const rgb = [1, 3, 5].map((i) => {
    const v = parseInt(hex.slice(i, i + 2), 16) / 255;
    return v <= 0.03928 ? v / 12.92 : ((v + 0.055) / 1.055) ** 2.4;
  });
  return 0.2126 * rgb[0] + 0.7152 * rgb[1] + 0.0722 * rgb[2];
}

function contrast(c1: string, c2: string): number {
  const [l1, l2] = [luminance(c1), luminance(c2)].sort((a, b) => b - a);
  return (l1 + 0.05) / (l2 + 0.05);
}

function ColorContrastChecker() {
  const [fg, setFg] = useState('#000000');
  const [bg, setBg] = useState('#ffffff');
  const ratio = contrast(fg.slice(1), bg.slice(1));

  return (
