      <label>ļ░░Ļ▓Įņāē <input type="color" value={bg} onChange={(e) => setBg(e.target.value)} /></label>
      <div style={{ background: bg, color: fg, padding: 12, borderRadius: 6 }}>ļ»Ėļ”¼ļ│┤ĻĖ░ ĒģŹņŖżĒŖĖ</div>
      <p style={{ margin: 0 }}>ļ¬ģņĢöļ╣ä: <strong>{ratio.toFixed(2)}:1</strong> ŌĆö {ratio >= 7 ? 'AAA' : ratio >= 4.5 ? 'AA' : ratio >= 3 ? 'AA (Ēü░ ĻĖĆņö©)' : 'ņŗżĒī©'}</p>
    </div>
  );
}

