interface Props { initialTags?: string[]; onChange?: (tags: string[]) => void; }

function TagEditor({ initialTags = [], onChange }: Props) {
  const [tags, setTags] = useState<string[]>(initialTags);
  const [input, setInput] = useState('');

  const add = () => {
    const trimmed = input.trim();
    if (!trimmed || tags.includes(trimmed)) return;
    const next = [...tags, trimmed];
    setTags(next); onChange?.(next); setInput('');
  };

  const remove = (tag: string) => {
    const next = tags.filter((t) => t !== tag);
    setTags(next); onChange?.(next);
  };

  return (
    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6, padding: 8, border: '1px solid #d1d5db', borderRadius: 8, minHeight: 44 }}>
      {tags.map((tag) => (
