          {tag}
          <button onClick={() => remove(tag)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#1d4ed8', fontSize: 14, lineHeight: 1, padding: 0 }}>├Ś</button>
        </span>
      ))}
      <input value={input} onChange={(e) => setInput(e.target.value)}
        onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ',') { e.preventDefault(); add(); } }}
        placeholder="Ēā£ĻĘĖ ņ×ģļĀź Ēøä Enter" style={{ border: 'none', outline: 'none', minWidth: 120, fontSize: 13 }} />
    </div>
  );
}

export default TagEditor;

import { useState, useCallback } from 'react';

function useTableSelection(ids: string[]) {
  const [selected, setSelected] = useState<Set<string>>(new Set());

  const toggleAll = useCallback(() => {
    setSelected((prev) =>
      prev.size === ids.length ? new Set() : new Set(ids)
    );
  }, [ids]);

  const toggleRow = useCallback((id: string) => {
    setSelected((prev) => {
      const next = new Set(prev);
      next.has(id) ? next.delete(id) : next.add(id);
      return next;
    });
  }, []);

  const isSelected = useCallback((id: string) => selected.has(id), [selected]);
  const isAllSelected = selected.size === ids.length && ids.length > 0;
  const clear = useCallback(() => setSelected(new Set()), []);

  return { selected, toggleAll, toggleRow, isSelected, isAllSelected, clear };
}

export default useTableSelection;

