import { useState, useCallback } from 'react';

interface Toast { id: string; message: string; type: 'info' | 'success' | 'error'; }

function useToastStack() {
  const [toasts, setToasts] = useState<Toast[]>([]);

  const push = useCallback((message: string, type: Toast['type'] = 'info', duration = 3000) => {
    const id = crypto.randomUUID();
    setToasts((prev) => [...prev, { id, message, type }]);
    setTimeout(() => setToasts((prev) => prev.filter((t) => t.id !== id)), duration);
  }, []);

  const dismiss = useCallback((id: string) =>
    setToasts((prev) => prev.filter((t) => t.id !== id)), []);

  return { toasts, push, dismiss };
}

export default useToastStack;

import { useRef, useState, useCallback } from 'react';

interface Props { children: React.ReactNode; initialPos?: { x: number; y: number }; }

function FloatingButton({ children, initialPos = { x: 24, y: 24 } }: Props) {
  const [pos, setPos] = useState(initialPos);
  const dragging = useRef(false);
  const offset = useRef({ x: 0, y: 0 });

  const onMouseDown = useCallback((e: React.MouseEvent) => {
    dragging.current = true;
    offset.current = { x: e.clientX - pos.x, y: e.clientY - pos.y };
  }, [pos]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    if (!dragging.current) return;
    setPos({ x: e.clientX - offset.current.x, y: e.clientY - offset.current.y });
  }, []);

  const onMouseUp = useCallback(() => { dragging.current = false; }, []);

  return (
    <div onMouseDown={onMouseDown}
      style={{ position: 'fixed', left: pos.x, top: pos.y, cursor: 'grab', userSelect: 'none', zIndex: 999 }}
      onMouseMove={(e) => onMouseMove(e.nativeEvent)} onMouseUp={onMouseUp} onMouseLeave={onMouseUp}>
      {children}
    </div>
  );
}

export default FloatingButton;

import { useEffect, useRef } from 'react';

function usePreviousValue<T>(value: T): { current: T; previous: T | undefined } {
  const previousRef = useRef<T | undefined>(undefined);
  const currentRef = useRef<T>(value);

  useEffect(() => {
    previousRef.current = currentRef.current;
    currentRef.current = value;
  });

  return { current: value, previous: previousRef.current };
}

export default usePreviousValue;

